insert into public.normativa_requisitos (id, norma_id, articulo, descripcion_corta, descripcion_oficial, code, airtable_id, orden) values
  ('d7814fae-6c09-5e8b-b40e-2f7a24065abe', '517ceb6c-31ad-5571-9aba-d0b08144ab3b', 'Art. 10', 'Si no hay planos confiables de instalaciones, realizar sondeos supervisados por técnico competente; registrar resultados en legajo.', 'Si no hay planos confiables, realizar sondeos supervisados por técnico competente; registrar en legajo.', 'Art. 10', 'rec02LP8j8wP444DF', 1),
  ('97e9802d-6ae0-5ab1-8d65-b7c2660c85f2', '1f4f433c-3a64-55ac-a98e-005073ea6d92', NULL, 'Presentar el Relevamiento General de Riesgos Laborales (RGRL) ante la ART dentro de los 30 días desde la afiliación.', 'RESOLUCION SRT Nº 415/2002. PLAZOS Y FORMAS DE CUMPLIMIENTO DE LA REMISION DE INFORMACION. ABROGACION DE LA CIRCULAR N° 5/2003 DE LA GERENCIA DE CONTROL, FISCALIZACION Y AUDITORIA DE LA S.R.T.
ANEXO I REGISTRO DE SUSTANCIAS Y AGENTES CANCERIGENOS ANEXO II Formulario declaración de los estudios ambientales y/o Biológicos efectuados a las Sustancias y Agentes Cancerígenos conforme lo determinado en el Formulario ANEXO III CODIGOS DE SUSTANCIAS Y AGENTES CANCERIGENOS', NULL, 'rec09fwuUXMAdF1Zt', 1),
  ('1f08b6e6-c60e-509b-bb97-86b21132d025', '19b0402e-1783-536f-afc1-161cd5c7a030', 'Anexo II ítem 2.a', 'El Servicio de HyS debe verificar diariamente el estado del suelo, paredes de la excavación y muros lindantes antes de iniciar los trabajos.', 'El Servicio de H&S debe verificar diariamente el estado del suelo, paredes de la excavación y muros lindantes antes de iniciar los trabajos.', 'Anexo II ítem 2.a', 'rec0IPWlZQUbCF5OO', 1),
  ('6671289c-7bf7-5ffa-8267-3883ac9d1240', '3ce22547-d41a-56ee-a568-4fe6e1959ca6', 'Art. 237 - Cap. 9', 'Los andamios metálicos tubulares deben estar reforzados en sentido diagonal, longitudinal y transversal.', 'Reforzados en sentido diagonal; longitudinal y transversalmente', 'Art. 237 - Cap. 9', 'rec0SiqIjTt7BrMuA', 1),
  ('cf40862c-63c7-518d-b8b2-d3a42f77b56a', '19b0402e-1783-536f-afc1-161cd5c7a030', 'Art. 3', 'Garantizar uso de casco, arnés con cabo de vida cuando corresponda, calzado de seguridad y protección visual y respiratoria en demoliciones y excavaciones.', 'Garantizar uso de casco, arnés con cabo de vida cuando corresponda, calzado de seguridad y protección visual y respiratoria en tareas de demolición y excavación.', 'Art. 3', 'rec0egCtT8Q9Tk9gW', 2),
  ('a4e91023-e3df-5ade-bc5b-b6dd85a887ec', '517ceb6c-31ad-5571-9aba-d0b08144ab3b', 'Anexo ítem 30', 'En ambientes con contaminantes, instalar ventilación forzada antiexplosiva, medir contaminantes, definir EPP y usar iluminación antiexplosiva a muy baja tensión (24/12 V).', 'En ambientes con contaminantes, instalar ventilación forzada antiexplosiva, medir contaminantes y definir EPP. Usar iluminación antiexplosiva a muy baja tensión (24/12 V). Cumplir Res. SRT 953/2010.', 'Anexo ítem 30', 'rec0gkZWPUZXlCnu2', 2),
  ('f66aa4f5-1d91-5776-9bb0-d0ca6c87a7d9', '77c75448-3749-5266-baa6-7789f64f5dab', 'Cap. I (Art. 1-4)', 'Cumplir las normas complementarias de la Ley 27.348: agotar la vía administrativa, depositar indemnizaciones en cuenta sueldo y registrar prestadores médicos; texto ordenado en 6 meses.', 'Normas complementarias: Exige agotar vía administrativa; ajustes RIPTE; depósito de indemnizaciones en cuenta sueldo; registro de prestadores médicos; reintegros de prestaciones; normas de orden público y texto ordenado en 6 meses.', 'Cap. I (Art. 1-4)', 'rec0qlgMY4oXSjzQt', 1),
