  ('175f4f4d-5891-5a88-9f6b-5eb0d5f7858b', '08d3fec6-baaa-5daa-b88e-c07c22e3cd0b', 'Art. 1', 'El empleador o comitente debe presentar el Aviso de Inicio de Obra a la ART antes de comenzar cualquier tarea.', 'El empleador/comitente debe presentar a la ART el aviso de inicio de obra.', 'Art. 1', 'recEJtzKjFtbNEIAK', 2),
