  ('3c7622d1-f1bf-5237-869a-aaf051e19cbf', 'b644032f-ddcb-5da9-b6ed-6f32985e1844', 'Art. 4', 'Titulares y explotadores son responsables de cumplir el Sistema.', 'Los titulares, explotadores o productores de eventos son responsables del cumplimiento del Sistema de Autoprotección.', 'Art. 4', 'recPVUAmhhmxs6Ax7', 8),
